const store = $.stanz({ count: 0 });

// 在組件中
export default {
  data: {
    store: {}
  },
  proto:{
    increment() {
        store.count++; // 所有引用瞭 store.count 的組件都會自動更新
    }
  },
  attached() {
    // 直接引用狀態對象的屬性
    this.store = store;
  },
  detached(){
    this.store = {}; // 組件銷毀時，清空掛載的狀態數據
  }
};
